from typing import List

class Solution:
    def isPossibleToSplit(self, nums: List[int]) -> bool:
        n = len(nums)
        half = n // 2

        cnt = {}
        for x in nums:
            cnt[x] = cnt.get(x, 0) + 1

        # nums1 can take at most one of each distinct value,
        # so it needs at least `half` distinct values.
        return len(cnt) >= half
